__global__ void naive_conv2d_fprop(
    const half* __restrict__ input,   // [N, H, W, C]
    const half* __restrict__ filter,  // [K, R, S, C]
    half* __restrict__ output,        // [N, P, Q, K]
    int N, int H, int W, int C, int K, int R, int S,
    int P, int Q, int pad_h, int pad_w, int stride_h, int stride_w) {
    // Each thread computes one output element
    int n = blockIdx.z;
    int k = blockIdx.x * blockDim.x + threadIdx.x;
    int pq = blockIdx.y * blockDim.y + threadIdx.y;
    int p = pq / Q, q = pq % Q;

    if (k < K && p < P && q < Q) {
        float sum = 0.0f;
        for (int r = 0; r < R; r++) {
            for (int s = 0; s < S; s++) {
                int h = p * stride_h - pad_h + r;
                int w = q * stride_w - pad_w + s;
                if (h >= 0 && h < H && w >= 0 && w < W) {
                    for (int c = 0; c < C; c++) {
                        float in_val = __half2float(input[n*H*W*C + h*W*C + w*C + c]);
                        float flt_val = __half2float(filter[k*R*S*C + r*S*C + s*C + c]);
                        sum += in_val * flt_val;
                    }
                }
            }
        }
        output[n*P*Q*K + p*Q*K + q*K + k] = __float2half(sum);
    }
}

__global__ void naive_conv2d_dgrad(
    const half* __restrict__ grad_output,  // [N, P, Q, K]
    const half* __restrict__ filter,       // [K, R, S, C]
    half* __restrict__ grad_input,         // [N, H, W, C]
    int N, int H, int W, int C, int K, int R, int S,
    int P, int Q, int pad_h, int pad_w, int stride_h, int stride_w) {
    // Each thread computes gradient for one input element
    int n = blockIdx.z;
    int c = blockIdx.x * blockDim.x + threadIdx.x;
    int hw = blockIdx.y * blockDim.y + threadIdx.y;
    int h = hw / W, w = hw % W;

    if (c < C && h < H && w < W) {
        float sum = 0.0f;
        for (int r = 0; r < R; r++) {
            for (int s = 0; s < S; s++) {
                // Reverse the filter application
                int p = (h + pad_h - r) / stride_h;
                int q = (w + pad_w - s) / stride_w;
                if (p >= 0 && p < P && q >= 0 && q < Q &&
                    (h + pad_h - r) % stride_h == 0 &&
                    (w + pad_w - s) % stride_w == 0) {
                    for (int k = 0; k < K; k++) {
                        float go_val = __half2float(grad_output[n*P*Q*K + p*Q*K + q*K + k]);
                        float flt_val = __half2float(filter[k*R*S*C + r*S*C + s*C + c]);
                        sum += go_val * flt_val;
                    }
                }
            }
        }
        grad_input[n*H*W*C + h*W*C + w*C + c] = __float2half(sum);
    }
}

__global__ void naive_conv2d_wgrad(
    const half* __restrict__ grad_output,  // [N, P, Q, K]
    const half* __restrict__ input,        // [N, H, W, C]
    half* __restrict__ grad_filter,        // [K, R, S, C]
    int N, int H, int W, int C, int K, int R, int S,
    int P, int Q, int pad_h, int pad_w, int stride_h, int stride_w) {
    // Each thread computes one filter gradient element
    int k = blockIdx.x * blockDim.x + threadIdx.x;
    int rsc = blockIdx.y * blockDim.y + threadIdx.y;
    int r = rsc / (S * C), s = (rsc / C) % S, c = rsc % C;

    if (k < K && r < R && s < S && c < C) {
        float sum = 0.0f;
        for (int n = 0; n < N; n++) {
            for (int p = 0; p < P; p++) {
                for (int q = 0; q < Q; q++) {
                    int h = p * stride_h - pad_h + r;
                    int w = q * stride_w - pad_w + s;
                    if (h >= 0 && h < H && w >= 0 && w < W) {
                        float go_val = __half2float(grad_output[n*P*Q*K + p*Q*K + q*K + k]);
                        float in_val = __half2float(input[n*H*W*C + h*W*C + w*C + c]);
                        sum += go_val * in_val;
                    }
                }
            }
        }
        grad_filter[k*R*S*C + r*S*C + s*C + c] = __float2half(sum);
    }
}

__global__ void naive_conv3d_fprop(half* input, half* filter, half* output,
    int N, int D, int H, int W, int C, int K, int T, int R, int S) {
    // Naive 8-nested loop: O(N*D*H*W*K*T*R*S*C)
    int n = blockIdx.x, d = blockIdx.y, h = blockIdx.z;
    for (int w = 0; w < W; w++) {
        for (int k = threadIdx.x; k < K; k += blockDim.x) {
            float sum = 0.0f;
            for (int t = 0; t < T; t++) {
                for (int r = 0; r < R; r++) {
                    for (int s = 0; s < S; s++) {
                        for (int c = 0; c < C; c++) {
                            int dd = d + t - T/2, hh = h + r - R/2, ww = w + s - S/2;
                            if (dd >= 0 && dd < D && hh >= 0 && hh < H && ww >= 0 && ww < W) {
                                // Scalar loads, no vectorization
                                half in_val = input[((n*D + dd)*H + hh)*W*C + ww*C + c];
                                half flt_val = filter[((k*T + t)*R + r)*S*C + s*C + c];
                                sum += __half2float(in_val) * __half2float(flt_val);
                            }
                        }
                    }
                }
            }
            output[((n*D + d)*H + h)*W*K + w*K + k] = __float2half(sum);
        }
    }
}

__global__ void naive_trmm_right_lower_unit(float* A, float* B, float* D,
    int M, int N) {
    // D = B * A where A is lower triangular with unit diagonal
    // Naive implementation: doesn't exploit triangular structure
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < N; k++) {
            float a_val;
            if (k > col) {
                a_val = 0.0f;  // Above diagonal in lower triangular
            } else if (k == col) {
                a_val = 1.0f;  // Unit diagonal
            } else {
                a_val = A[col * N + k];  // Below diagonal
            }
            sum += B[row * N + k] * a_val;
        }
        D[row * N + col] = sum;
    }
}

__global__ void naive_syrk_upper(float* A, float* C, float alpha, float beta,
    int N, int K) {
    // C = alpha * A * A^T + beta * C where C is symmetric (only upper stored)
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < N && col < N && row <= col) {  // Only compute upper triangle
        float sum = 0.0f;
        for (int k = 0; k < K; k++) {
            // A[row,k] * A[col,k] (A^T means we use col index for second A)
            sum += A[row * K + k] * A[col * K + k];
        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
    // Lower triangle: threads do nothing (50% waste)
}

__global__ void naive_symm_left_lower(float* A, float* B, float* C,
    float alpha, float beta, int M, int N) {
    // C = alpha * A * B + beta * C where A is symmetric (lower triangle stored)
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < M; k++) {
            // Access A[row,k] but A only stores lower triangle
            float a_val;
            if (row >= k) {
                a_val = A[row * M + k];  // Lower triangle: direct access
            } else {
                a_val = A[k * M + row];  // Upper triangle: access symmetric element
            }
            sum += a_val * B[k * N + col];
        }
        C[row * N + col] = alpha * sum + beta * C[row * N + col];
    }
}

__global__ void naive_complex_gemm_interleaved(half2* A, half2* B, half2* C,
    int M, int N, int K) {
    // Complex GEMM with interleaved layout: [real0, imag0, real1, imag1, ...]
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < M && col < N) {
        float2 sum = {0.0f, 0.0f};
        for (int k = 0; k < K; k++) {
            // Load interleaved complex numbers
            half2 a = A[row * K + k];  // (real, imag)
            half2 b = B[k * N + col];

            // Complex multiply: (a.real + i*a.imag) * (b.real + i*b.imag)
            // = (a.real*b.real - a.imag*b.imag) + i*(a.real*b.imag + a.imag*b.real)
            float ar = __half2float(a.x), ai = __half2float(a.y);
            float br = __half2float(b.x), bi = __half2float(b.y);
            sum.x += ar * br - ai * bi;  // Real part
            sum.y += ar * bi + ai * br;  // Imag part
        }
        C[row * N + col] = make_half2(__float2half(sum.x), __float2half(sum.y));
    }
}

